/* eslint-disable react-hooks/rules-of-hooks */
import { test as base, expect } from '@playwright/test';

/**
 * MMS E2E Test Fixtures
 *
 * Provides shared fixtures and helpers for E2E tests.
 * Use these fixtures for consistent test setup and teardown.
 */

// Extended test fixture with MMS-specific helpers
export const test = base.extend<{
  /**
   * Navigate to the MMS canvas and wait for it to load
   */
  loadCanvas: () => Promise<void>;
  /**
   * Set zoom level (0-20)
   */
  setZoomLevel: (level: number) => Promise<void>;
  /**
   * Wait for canvas to finish rendering
   */
  waitForCanvasReady: () => Promise<void>;
}>({
  loadCanvas: async ({ page }, use) => {
    await use(async () => {
      await page.goto('/');
      // Wait for the main app container to be visible
      await page.waitForSelector('[data-testid="mms-app"]', {
        state: 'visible',
        timeout: 10_000,
      });
    });
  },

  setZoomLevel: async ({ page }, use) => {
    await use(async (level: number) => {
      // Use keyboard shortcut or direct manipulation
      // Levels 1-5 correspond to zoom presets
      if (level >= 1 && level <= 5) {
        await page.keyboard.press(`Digit${level}`);
      }
      // Wait for zoom animation to complete
      await page.waitForTimeout(300);
    });
  },

  waitForCanvasReady: async ({ page }, use) => {
    await use(async () => {
      // Wait for canvas container to be present
      await page.waitForSelector('[data-testid="infinite-canvas"]', {
        state: 'visible',
        timeout: 10_000,
      });
      // Wait for loading spinner to disappear
      const spinner = page.locator('[data-testid="canvas-loading"]');
      if (await spinner.count() > 0) {
        await spinner.waitFor({ state: 'hidden', timeout: 15_000 });
      }
    });
  },
});

// Re-export expect for convenience
export { expect };

/**
 * Zoom level boundaries per spec 006
 */
export const ZOOM_LEVELS = {
  STRATEGIC_MIN: 0,
  STRATEGIC_MAX: 4,
  TACTICAL_WIDE_MIN: 4,
  TACTICAL_WIDE_MAX: 8,
  TACTICAL_MIN: 8,
  TACTICAL_MAX: 12,
  OPERATIONAL_MIN: 12,
  OPERATIONAL_MAX: 16,
  DETAIL_MIN: 16,
  DETAIL_MAX: 20,
} as const;

/**
 * Test data-testid selectors used across the app
 */
export const SELECTORS = {
  // Layout components
  APP: '[data-testid="mms-app"]',
  HEADER: '[data-testid="header"]',
  TOOLBAR: '[data-testid="toolbar"]',
  SIDEBAR: '[data-testid="sidebar"]',
  STATUS_BAR: '[data-testid="status-bar"]',

  // Canvas
  CANVAS: '[data-testid="infinite-canvas"]',
  CANVAS_LOADING: '[data-testid="canvas-loading"]',

  // View-specific
  STRATEGIC_VIEW: '[data-testid="strategic-heatmap"]',
  TACTICAL_WIDE_VIEW: '[data-testid="tactical-wide-view"]',
  TACTICAL_VIEW: '[data-testid="tactical-gantt"]',
  OPERATIONAL_VIEW: '[data-testid="operational-detail"]',
  DETAIL_VIEW: '[data-testid="detail-view"]',

  // PM blocks
  PM_BLOCK: '[data-testid^="pm-block-"]',

  // Overlays
  MANHOUR_OVERLAY: '[data-testid="manhour-overlay"]',
  DRIFT_OVERLAY: '[data-testid="drift-overlay"]',
  SCENARIO_COMPARISON: '[data-testid="scenario-comparison"]',
  BASELINE_SHADOW: '[data-testid="baseline-shadow"]',

  // Dialogs - BlueprintJS v6 uses bp6-dialog class and renders to portal
  // Note: data-testid on Dialog component doesn't forward to DOM element
  KEYBOARD_SHORTCUTS_DIALOG: '[role="dialog"].bp6-dialog',
  DRAG_CONFIRMATION_DIALOG: '[role="dialog"].bp6-dialog',
} as const;

