/**
 * MMS Simulation Service Unit Tests
 *
 * Tests for the Simulation Service (Simulation Engine) covering:
 * - Service initialization and singleton pattern
 * - Type definitions for scenarios, deltas, and comparisons
 * - Scenario lifecycle management
 * - Event-sourced delta operations
 * - Scenario materialization logic
 * - Comparison calculations
 * - Promotion to baseline workflow
 *
 * Note: These tests use Bun's test framework and document expected behavior.
 * Integration tests with actual database should be in a separate test suite.
 *
 * @see src/services/simulation.ts
 * @see specs/004-domain-services.md Section 4.9
 */

import { describe, test, expect } from 'bun:test';
import {
  SimulationService,
  getSimulationService,
  type ScenarioStatus,
  type DeltaType,
  type EntityType,
  type ForkSource,
  type CreateScenarioRequest,
  type ScenarioChange,
  type MaterializedPmRecord,
  type MaterializedScenario,
  type PMDifference,
  type PMDifferenceSummary,
  type ManhourDifferenceSummary,
  type CostDifferenceSummary,
  type ScenarioComparisonResult,
  type ScenarioListFilters,
  type ScenarioPaginationOptions,
  type PaginatedScenarioResult,
  type ScenarioWithMeta,
  type PromoteScenarioRequest,
} from './simulation';
import {
  NotFoundError,
  ValidationError,
  BusinessRuleError,
} from '../lib/errors';

describe('SimulationService', () => {
