import { test, expect, SELECTORS } from '../fixtures/test-fixtures';

/**
 * Smoke tests to verify the MMS application loads correctly.
 * These tests are the most basic verification that the app is working.
 */

test.describe('MMS Application Smoke Tests', () => {
  test('should load the application without errors', async ({ page }) => {
    await page.goto('/');

    // Verify the page title
    await expect(page).toHaveTitle(/MMS|Metro Fleet/);

    // Verify no console errors
    const errors: string[] = [];
    page.on('console', (msg) => {
      if (msg.type() === 'error') {
        errors.push(msg.text());
      }
    });

    // Give the app time to initialize
    await page.waitForTimeout(2000);

    // Filter out expected errors (like missing API endpoints in test mode)
    const unexpectedErrors = errors.filter(
      (error) => !error.includes('Failed to fetch') && !error.includes('net::ERR')
    );

    expect(unexpectedErrors).toHaveLength(0);
  });

  test('should display the main layout components', async ({ page }) => {
    await page.goto('/');

    // Wait for app to load
    await page.waitForSelector(SELECTORS.APP, { timeout: 10_000 });

    // Verify header is visible
    const header = page.locator(SELECTORS.HEADER);
    await expect(header).toBeVisible();

    // Verify toolbar is visible
    const toolbar = page.locator(SELECTORS.TOOLBAR);
    await expect(toolbar).toBeVisible();

    // Verify sidebar is visible
    const sidebar = page.locator(SELECTORS.SIDEBAR);
    await expect(sidebar).toBeVisible();

    // Verify status bar is visible
    const statusBar = page.locator(SELECTORS.STATUS_BAR);
    await expect(statusBar).toBeVisible();
  });

  test('should display the infinite canvas', async ({ page }) => {
    await page.goto('/');

    // Wait for canvas to be ready
    await page.waitForSelector(SELECTORS.APP, { timeout: 10_000 });

    // Verify canvas container exists
    const canvas = page.locator(SELECTORS.CANVAS);
    await expect(canvas).toBeVisible();
  });

  test('should be responsive to keyboard events', async ({ page }) => {
    await page.goto('/');
    await page.waitForSelector(SELECTORS.APP, { timeout: 10_000 });

    // Focus the canvas
    const canvas = page.locator(SELECTORS.CANVAS);
    await canvas.focus();

    // Press ? to open keyboard shortcuts dialog
    await page.keyboard.press('Shift+Slash'); // ? key

    // Verify the keyboard shortcuts dialog appears
    const dialog = page.locator(SELECTORS.KEYBOARD_SHORTCUTS_DIALOG);
    await expect(dialog).toBeVisible({ timeout: 2000 });

    // Wait for dialog to be fully rendered and focusable
    await page.waitForTimeout(100);

    // Click the close button instead of Escape (more reliable for BlueprintJS dialogs)
    const closeButton = dialog.locator('button[aria-label="Close"]');
    await closeButton.click();

    // Give time for dialog close animation
    await expect(dialog).toBeHidden({ timeout: 2000 });
  });
});

