import { test, expect, SELECTORS } from '../fixtures/test-fixtures';

/**
 * Tests for keyboard shortcuts in the MMS canvas.
 * Verifies all shortcuts from spec 006.9.2 work correctly.
 */

test.describe('Keyboard Shortcuts', () => {
  test.beforeEach(async ({ page }) => {
    await page.goto('/');
    await page.waitForSelector(SELECTORS.APP, { timeout: 10_000 });

    // Focus the canvas for keyboard events
    const canvas = page.locator(SELECTORS.CANVAS);
    await canvas.focus();
  });

  test.describe('Help Dialog', () => {
    test('should open keyboard shortcuts dialog with ?', async ({ page }) => {
      await page.keyboard.press('Shift+Slash'); // ? key

      const dialog = page.locator(SELECTORS.KEYBOARD_SHORTCUTS_DIALOG);
      await expect(dialog).toBeVisible({ timeout: 2000 });
    });

    test('should close dialog with Escape', async ({ page }) => {
      await page.keyboard.press('Shift+Slash');
      const dialog = page.locator(SELECTORS.KEYBOARD_SHORTCUTS_DIALOG);
      await expect(dialog).toBeVisible();

      // Wait for dialog to be fully rendered
      await page.waitForTimeout(100);

      // Click the close button (more reliable for BlueprintJS dialogs)
      const closeButton = dialog.locator('button[aria-label="Close"]');
      await closeButton.click();
      await expect(dialog).toBeHidden({ timeout: 2000 });
    });

    test('should list all available shortcuts', async ({ page }) => {
      await page.keyboard.press('Shift+Slash');
      const dialog = page.locator(SELECTORS.KEYBOARD_SHORTCUTS_DIALOG);

      // Verify dialog contains shortcut tables (multiple tables for categories)
      const tables = dialog.locator('table');
      await expect(tables.first()).toBeVisible();
      // The dialog has 5 tables for different shortcut categories
      await expect(tables).toHaveCount(5);
    });
  });

  test.describe('Navigation Shortcuts', () => {
    test('should pan canvas with arrow keys', async ({ page }) => {
      // Get initial canvas position/state
      const canvas = page.locator(SELECTORS.CANVAS);

      // Press arrow keys
      await page.keyboard.press('ArrowRight');
      await page.waitForTimeout(100);
