import { defineConfig, devices } from '@playwright/test';

/**
 * MMS Playwright E2E Configuration
 *
 * Usage:
 *   bun run test:e2e          # Run all E2E tests
 *   bun run test:e2e:ui       # Run with UI mode
 *   bun run test:e2e:debug    # Run with debugger
 *
 * Environment Variables:
 *   CI=true           # Enables CI-specific settings (retries, no video)
 *   PLAYWRIGHT_SLOW   # Slow down test execution for debugging
 *   E2E_BASE_URL      # Override base URL (default: http://127.0.0.1:5173)
 *   VITE_PORT         # Port for Vite dev server (default: 0 = random)
 *
 * Dynamic Port Support:
 *   The webServer uses port 0 (random) by default. Playwright captures
 *   the actual port from server output and sets baseURL accordingly.
 */

// Use random port (0) by default for isolation; fallback to 5173 for CI/fixed scenarios
const VITE_PORT = process.env.VITE_PORT !== undefined ? parseInt(process.env.VITE_PORT) : 0;
const BASE_URL = process.env.E2E_BASE_URL || `http://127.0.0.1:${VITE_PORT || 5173}`;

export default defineConfig({
  // Test directory
  testDir: './tests/e2e',
  testMatch: '**/*.e2e.ts',

  // Timeout configuration
  timeout: 30_000, // 30 seconds per test
  expect: {
    timeout: 5_000, // 5 seconds for expect assertions
  },

  // Parallel execution
  fullyParallel: true,
  workers: process.env.CI ? 1 : undefined,

  // Retry configuration
  retries: process.env.CI ? 2 : 0,

  // Reporter configuration
  reporter: [
    ['html', { outputFolder: 'playwright-report', open: 'never' }],
    ['list'],
  ],

  // Global setup/teardown
  globalSetup: undefined,
  globalTeardown: undefined,

  // Shared settings for all projects
  use: {
    // Base URL for MMS frontend (dynamic port supported)
    baseURL: BASE_URL,

    // Trace collection for debugging
    trace: process.env.CI ? 'on-first-retry' : 'retain-on-failure',

    // Screenshot on failure
    screenshot: 'only-on-failure',

    // Video recording
    video: process.env.CI ? 'off' : 'retain-on-failure',

    // Viewport for desktop-only app (spec 006: minimum 1024px viewport)
    viewport: { width: 1280, height: 720 },

    // Action timeout
    actionTimeout: 10_000,

    // Navigation timeout
    navigationTimeout: 15_000,

    // Locale (MMS operates in Hong Kong timezone per spec)
    locale: 'en-US',
    timezoneId: 'Asia/Hong_Kong',
  },

  // Browser projects
  projects: [
    {
      name: 'chromium',
      use: { ...devices['Desktop Chrome'] },
    },
    // Firefox and WebKit can be enabled for cross-browser testing
    // {
    //   name: 'firefox',
    //   use: { ...devices['Desktop Firefox'] },
    // },
    // {
    //   name: 'webkit',
    //   use: { ...devices['Desktop Safari'] },
    // },
  ],

  // Web server configuration - starts dev server before tests with random port
  webServer: {
    command: `VITE_PORT=${VITE_PORT} bun run dev`,
    port: VITE_PORT || undefined, // Playwright detects port from server output when 0
    reuseExistingServer: !process.env.CI,
    timeout: 120_000, // 2 minutes to start server
    stdout: 'pipe',
    stderr: 'pipe',
  },

  // Output directory for test artifacts
  outputDir: 'test-results',
});

/**
 * MMS Error Classes Unit Tests
 *
 * Tests for error handling infrastructure covering:
 * - Error code assignments (correct codes per category)
 * - HTTP status code mappings
 * - toJSON() serialization for API responses
 * - isMmsError() type guard
 * - toMmsError() conversion from unknown errors
 * - Error-specific properties and options
 *
 * These tests are CRITICAL as error classes provide consistent error handling
 * across the 12-year government contract, enabling proper API responses,
 * logging, and client-side error handling.
