/**
 * Demo Data Generator Types
 *
 * Type definitions for the MMS demo data generation system.
 * Supports 128-train fleet generation with historical data.
 *
 * @see specs/009-demo-application.md
 */

export interface DemoFleet {
  code: string;
  name: string;
  manufacturer: string;
  model: string;
  trainCount: number;
  carsPerTrain: number;
  displayColor: string;
  dailyKmRange: { min: number; max: number };
  commissioningRange: { start: Date; end: Date };
}

export interface DemoPMRule {
  pmCode: string;
  pmName: string;
  intervalKm: number;
  intervalMonths: number;
  estimatedHours: number;
  trackType: 'LIGHT' | 'HEAVY' | 'OVERHAUL' | 'STABLING';
  satisfiesCodes: string[] | null;
  displayColor: string;
  displayPriority: number;
}

export interface DemoTrain {
  id: string;
  fleetId: string;
  fleetCode: string;
  trainNumber: string;
  commissioningDate: Date;
  currentMileageKm: number;
  estimatedDailyKm: number;
  fitnessStatus: 'FIT' | 'RESTRICTED' | 'GROUNDED';
  displayColor: string;
}

export interface DemoPMHistory {
  trainId: string;
  pmTypeId: string;
  pmCode: string;
  completionDate: Date;
  completedMileageKm: number;
}

export interface DemoMileageReading {
  trainId: string;
  readingDate: Date;
  rawReading: number;
  adjustedReading: number;
  dailyKm: number;
}

export interface DemoServiceDemand {
  fleetId: string;
  dayType: 'WEEKDAY' | 'SATURDAY' | 'SUNDAY' | 'HOLIDAY';
  minTrainsRequired: number;
  peakAmTrains: number;
  peakPmTrains: number;
}

export interface GeneratorConfig {
  /** Number of trains to generate (default: 128) */
  trainCount: number;
  /** Years of historical data to generate (default: 5) */
  historyYears: number;
  /** Enable bow-wave scenario (clusters 20% of fleet PM into Q2 2027) */
  enableBowWave: boolean;
  /** Random seed for reproducible generation */
  seed?: number;
}

export interface GeneratedData {
  depots: Array<{
    id: string;
    code: string;
    name: string;
    location: string;
    timezone: string;
  }>;
  fleets: Array<{
    id: string;
    code: string;
    name: string;
    manufacturer: string;
    model: string;
    baseDepotId: string;
    carsPerTrain: number;
  }>;
  trains: DemoTrain[];
  pmTypes: Array<{
    id: string;
    fleetId: string;
    pmCode: string;
    pmName: string;
    intervalKm: number;
    intervalMonths: number;
    estimatedHours: number;
    trackType: string;
    satisfiesCodes: string[] | null;
    displayColor: string;
    displayPriority: number;
  }>;
  pmHistory: DemoPMHistory[];
  mileageReadings: DemoMileageReading[];
  serviceDemand: DemoServiceDemand[];
  tracks: Array<{
    id: string;
    depotId: string;
    trackNumber: string;
    trackType: string;
    maxTrainLengthM: number;
    hasOverheadCrane: boolean;
    hasPitAccess: boolean;
  }>;
}

/**
 * Projected PM event for future scheduling
 */
export interface ProjectedPM {
  trainId: string;
  trainNumber: string;
  fleetCode: string;
  pmTypeId: string;
  pmCode: string;
  projectedDate: Date;
  projectedMileage: number;
  estimatedHours: number;
  displayColor: string;
}

/**
 * Monthly PM density for heatmap visualization
 */
export interface MonthlyPMDensity {
  year: number;
  month: number;
  yearMonth: string; // 'YYYY-MM' format
  totalPMs: number;
  pmsByType: Record<string, number>;
  isCritical: boolean; // >15 PMs/month
  manHours: number;
}

/**
 * Bow-wave analysis results
 */
export interface BowWaveAnalysis {
  /** Peak month with highest C4 concentration */
  peakMonth: {
    yearMonth: string;
    c4Count: number;
    percentage: number;
  };
  /** Peak quarter (Q1-Q4 YYYY) */
  peakQuarter: {
    quarter: string;
    c4Count: number;
    percentage: number;
  };
  /** Whether 40% C4 overlap threshold is exceeded */
  hasOverlapViolation: boolean;
  /** Total trains affected by bow-wave */
  affectedTrainCount: number;
  /** Estimated capital risk in millions */
  capitalRiskMillions: number;
  /** Man-hour capacity analysis */
  capacityAnalysis: {
    peakWeekHours: number;
    weeklyCapacity: number;
    overloadPercentage: number;
  };
  /** Risk severity level */
  riskLevel: 'LOW' | 'MEDIUM' | 'HIGH' | 'CRITICAL';
}

/**
 * Gantt bar data for visualization
 */
export interface GanttBar {
  trainId: string;
  trainNumber: string;
  fleetCode: string;
  pmCode: string;
  startDate: string;
  endDate: string;
  estimatedHours: number;
  displayColor: string;
}

/**
 * Complete bow-wave scenario analysis output
 */
export interface BowWaveScenarioOutput {
  /** Projected PMs for the analysis horizon */
  projectedPMs: ProjectedPM[];
  /** Monthly PM density for heatmap */
  monthlyDensity: MonthlyPMDensity[];
  /** Bow-wave analysis summary */
  analysis: BowWaveAnalysis;
  /** Gantt bar data for tactical view */
  ganttBars: GanttBar[];
  /** Analysis horizon in years */
  horizonYears: number;
  /** Fleet size used for calculations */
  fleetSize: number;
}

