 * Create a function that fails N times then succeeds
 */
function createFailingFunction<T>(failCount: number, successValue: T, error?: Error) {
  let attempts = 0;
  return async () => {
    attempts++;
    if (attempts <= failCount) {
      throw error ?? new Error(`Attempt ${attempts} failed`);
    }
    return successValue;
  };
}

/**
 * Create a function that always fails
 */
function createAlwaysFailingFunction(error?: Error) {
  return async () => {
    throw error ?? new Error('Always fails');
  };
}

/**
