/**
 * Tests for drag-and-drop PM rescheduling in the MMS canvas.
 * These tests verify the drag-drop interaction flow.
 *
 * Note: Full drag-drop testing requires PM blocks to be rendered,
 * which depends on data loading. These tests verify the infrastructure.
 */

test.describe('PM Drag and Drop', () => {
  test.beforeEach(async ({ page }) => {
    await page.goto('/');
    await page.waitForSelector(SELECTORS.APP, { timeout: 10_000 });

    // Focus the canvas for interactions
    const canvas = page.locator(SELECTORS.CANVAS);
    await canvas.focus();
  });

  test('should have canvas ready for drag interactions', async ({ page }) => {
    const canvas = page.locator(SELECTORS.CANVAS);
    await expect(canvas).toBeVisible();

    // Canvas should be focusable (required for keyboard shortcuts during drag)
    await canvas.focus();

    // Verify canvas is interactive
    const isFocused = await canvas.evaluate(el => document.activeElement === el);
    expect(isFocused).toBe(true);
  });

  test('should handle escape key during drag (cancellation)', async ({ page }) => {
    const canvas = page.locator(SELECTORS.CANVAS);
    await canvas.focus();

    // Simulate drag start (move would trigger drag state)
    await page.keyboard.press('Escape');
    await page.waitForTimeout(100);

    // Verify no confirmation dialog appeared (no active drag)
    const confirmDialog = page.locator(SELECTORS.DRAG_CONFIRMATION_DIALOG);
    await expect(confirmDialog).toBeHidden();
  });

  test('should show PM blocks when data is available', async ({ page }) => {
    // PM blocks are identified by data-testid starting with "pm-block-"
    const pmBlocks = page.locator(SELECTORS.PM_BLOCK);

    // Wait briefly for potential data loading
    await page.waitForTimeout(500);

    // Count PM blocks (may be 0 if no data loaded)
