/**
 * Demo Data Generator Tests
 *
 * Validates the MMS demo data generation system.
 * Ensures correct train counts, PM hierarchy, and data integrity.
 */

import { describe, expect, it } from 'bun:test';
import { generateDemoData, generateSQL, formatDate } from './generator';
import { DEMO_FLEETS, PM_RULES_BY_FLEET } from './data';

describe('Demo Data Generator', () => {
  describe('generateDemoData', () => {
    it('generates 128 trains by default', () => {
      const data = generateDemoData({ seed: 12345 });
      expect(data.trains.length).toBe(128);
    });

    it('generates configurable train count', () => {
      const data = generateDemoData({ trainCount: 50, seed: 12345 });
      expect(data.trains.length).toBe(50);
    });

    it('distributes trains across all fleets', () => {
      const data = generateDemoData({ trainCount: 128, seed: 12345 });

      const fleetCounts = new Map<string, number>();
      for (const train of data.trains) {
        const count = fleetCounts.get(train.fleetCode) || 0;
        fleetCounts.set(train.fleetCode, count + 1);
      }

      // Each fleet should have trains
      for (const fleet of DEMO_FLEETS) {
        expect(fleetCounts.get(fleet.code)).toBeGreaterThan(0);
      }
    });

    it('generates all three depots', () => {
      const data = generateDemoData({ seed: 12345 });
      expect(data.depots.length).toBe(3);

      const depotCodes = data.depots.map((d) => d.code);
      expect(depotCodes).toContain('KWL');
      expect(depotCodes).toContain('SIK');
      expect(depotCodes).toContain('PTD');
    });

    it('generates PM types for each fleet', () => {
      const data = generateDemoData({ seed: 12345 });

      const fleetPmTypes = new Map<string, string[]>();
      for (const pmType of data.pmTypes) {
        const fleet = data.fleets.find((f) => f.id === pmType.fleetId);
        if (fleet) {
          const codes = fleetPmTypes.get(fleet.code) || [];
          codes.push(pmType.pmCode);
          fleetPmTypes.set(fleet.code, codes);
        }
      }

      // Each fleet should have C1, C2, C3, C4, OH
      for (const fleet of DEMO_FLEETS) {
        const codes = fleetPmTypes.get(fleet.code) || [];
        expect(codes).toContain('C1');
        expect(codes).toContain('C2');
        expect(codes).toContain('C3');
        expect(codes).toContain('C4');
        expect(codes).toContain('OH');
      }
    });

    it('generates valid train numbers', () => {
      const data = generateDemoData({ trainCount: 128, seed: 12345 });

      for (const train of data.trains) {
        // Train number format: FLEET-NNN
        expect(train.trainNumber).toMatch(/^[A-Z]+-\d{3}$/);

        // Fleet code matches train number prefix
        expect(train.trainNumber.startsWith(train.fleetCode)).toBe(true);
      }
    });

    it('generates commissioning dates within fleet range', () => {
      const data = generateDemoData({ trainCount: 128, seed: 12345 });

      for (const train of data.trains) {
        const fleetConfig = DEMO_FLEETS.find((f) => f.code === train.fleetCode);
        expect(fleetConfig).toBeDefined();

        if (fleetConfig) {
          const commDate = train.commissioningDate;
          expect(commDate.getTime()).toBeGreaterThanOrEqual(
            fleetConfig.commissioningRange.start.getTime()
          );
          expect(commDate.getTime()).toBeLessThanOrEqual(
            fleetConfig.commissioningRange.end.getTime()
          );
        }
